import sys

def solve(N, S, R, A):
    calm_blocks = 0
    for i in range(N):
        for j in range(i, N):
            block = A[i:j+1]
            if sum(block) <= S and max(block) - min(block) <= R:
                calm_blocks += 1
    return calm_blocks

def main():
    N, S, R = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))
    print(solve(N, S, R, A))

if __name__ == "__main__":
    main()
